import * as React from "react";
import styled from "styled-components";

interface BaseProps {
  /** Label text to display */
  label: string;
  /** Whether to show in compact mode */
  compact?: boolean;
  /** Whether the item is highlighted */
  highlighted?: boolean;
  className?: string;
  style?: React.CSSProperties;
}

